//-------------------------------------------------------------------------
scwin.f_TogglePchsClntCls = function (pchsClntYn) {
  var chkArr = [chk_pchsClntCls1, chk_pchsClntCls2, chk_pchsClntCls3, chk_pchsClntCls4];
  if (pchsClntYn == true) {
    // 체크
    $c.gus.cfEnableObjects($p, chkArr);
  } else if (pchsClntYn == false) {
    $c.gus.cfDisableObjects($p, chkArr);
  }
};
scwin.f_validate = async function () {
  if (!(await $c.gus.cfValidate($p, [tbl_clnt, tbl_busi], null, true))) {
    return false;
  }
  if (chk_sellClntYn.getValue() == "0" && chk_pchsClntYn.getValue() == "0") {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["매출입구분"]);
    return false;
  }
  if ((await scwin.f_validateSellClnt()) == false) {
    return false;
  }
  if ((await scwin.f_validatePchsClnt()) == false) {
    return false;
  }
  return true;
};
scwin.f_validateSellClnt = async function () {
  if (chk_sellClntYn.getValue() == "0") {
    return true;
  }
  if ($c.gus.cfIsNull($p, lc_sellClntClsCd.getValue())) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_056, ["매출거래처구분"]);
    return false;
  }
  if (chk_bizDivBulkYn.getValue() == "0" && chk_bizDivCntrYn.getValue() == "0") {
    // 사업부문 항목 체크
    await $c.gus.cfAlertMsg($p, "사업부문은 매출거래처 필수입력 사항입니다.");
    chk_bizDivCntrYn.setValue("1"); // bizDivCntrYn.checked= true;
    return false;
  }
  if (chk_bizDomTplYn.getValue() == "0" && chk_bizDomTransYn.getValue() == "0" && chk_bizDomStvYn.getValue() == "0" && chk_bizDomStrYn.getValue() == "0") {
    // 사업영역 항목 체크
    await $c.gus.cfAlertMsg($p, "사업영역은 매출거래처 필수입력 사항입니다.");
    return false;
  }
  if (ds_collMoneyCond.getTotalRow() == 0 && !(lc_intrlnsClsCd.getValue() != "02" && lc_sellClntClsCd.getValue() == "02")) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_053, ["수금조건"]);
    return false;
  }
  if (!(await $c.gus.cfValidate($p, [gr_collMoneyCond], null, true))) {
    return false;
  }
  if (scwin.f_ExistSameRowYn(ds_collMoneyCond, ["adptDt", "collMoneyAcctDeptCd", "stmtPrdClsCd", "stmtPrdDd", "collMoneyCntShtCd", "draftDdCnt", "collMoneyCrcCd"])) {
    await $c.gus.cfAlertMsg($p, "동일한 수금조건이 존재합니다.");
    return false;
  }
  return true;
};
scwin.f_validatePchsClnt = async function () {
  if (chk_pchsClntYn.getValue() == "0") {
    return true;
  }
  if (chk_transBizYn.getValue() == "0" && chk_transIntcdBizYn.getValue() == "0") {
    // 운송사업부분
    await $c.gus.cfAlertMsg($p, "운송사업구분은 매입거래처 필수입력 사항입니다.");
    return false;
  }
  if ((await scwin.f_validatePayCond()) == false) {
    return false;
  }
  if ((await scwin.f_validatePayAcnt()) == false) {
    return false;
  }
  return true;
};
scwin.f_validatePayCond = async function () {
  if (ds_payCond.getTotalRow() == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_053, ["지불조건"]);
    return false;
  }
  let validArray = [{
    id: "adptDt",
    name: "적용일자",
    mandatory: true
  }, {
    id: "payCycCd",
    name: "지급주기",
    mandatory: true
  }, {
    id: "payCntShtCd",
    name: "지급수단",
    mandatory: true
  }];
  let ret = await $c.gus.cfValidateGrid($p, gr_payCond, null, null, validArray, "지급조건");
  if (!ret) {
    return false;
  }
  if (scwin.f_ExistSameRowYn(ds_payCond, ["adptDt", "payAcctDeptCd", "mbssysVehclYn", "mchtClntNo", "payCycCd", "payDd", "payCntShtCd", "draftDdCntCd", "payCrcCd", "cashRt", "draftRt"])) {
    await $c.gus.cfAlertMsg($p, "동일한 지불조건이 존재합니다.");
    return false;
  }
  for (var i = 0; i < ds_payCond.getTotalRow(); i++) {
    if (ds_payCond.getCellData(i, "payCntShtCd") == "50" && $c.gus.cfIsNull($p, ds_payCond.getCellData(i, "draftDdCntCd"))) {
      await $c.gus.cfAlertMsg($p, "지급조건의 지급수단이 실물어음,전자결제일경우 어음일수를 입력하셔야 합니다.");
      gr_payCond.setFocusedCell(i, "draftDdCntCd");
      return false;
    }
    if (ds_payCond.getCellData(i, "payCntShtCd") == "25" && $c.gus.cfIsNull($p, ds_payCond.getCellData(i, "draftDdCntCd")) && ds_payCond.getCellData(i, "cashRt") != "100") {
      await $c.gus.cfAlertMsg($p, "지급조건의 지급수단이 실물어음,전자결제일경우 어음일수를 입력하셔야 합니다.");
      gr_payCond.setFocusedCell(i, "draftDdCntCd");
      return false;
    }
    if (ds_payCond.getCellData(i, "mbssysVehclYn") == "1" && $c.gus.cfIsNull($p, ds_payCond.getCellData(i, "mchtClntNm"))) {
      await $c.gus.cfAlertMsg($p, "지급조건이 회원제차량인 경우 화주거래처 입력은 필수사항입니다.");
      gr_payCond.setFocusedCell(i, "mchtClntNm");
      return false;
    }
  }
  return true;
};
scwin.f_validatePayAcnt = async function () {
  if (ds_payAcnt.getTotalRow() == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_053, ["지급계좌"]);
    return false;
  }
  if ((await $c.gus.cfValidate($p, [gr_payAcnt], null, true)) == false) {
    return false;
  }
  if (scwin.f_ExistSameRowYn(ds_payAcnt, ["adptDt", "payClsCd", "bankCd", "bankAcntNo", "dpstrNm", "elecStmtBankCd", "transfCmisDeductYn"])) {
    await $c.gus.cfAlertMsg($p, "동일한 지불계좌가 존재합니다.");
    return false;
  }
  return true;
};
