scwin.f_save = async function () {
  if (scwin.f_IsUpdated([ds_clnt, ds_busi, ds_collMoneyCond, ds_payCond, ds_payAcnt]) == false && scwin.f_IsPchsClntClsChnaged() == false) {
    await $c.gus.cfAlertMsg($p, "변경된 사항이 없습니다.");
    return false;
  }

  // 결제구분은 Bill 수령후를 선택할 수 없게함
  if (ds_collMoneyCond.getCellData(0, 'stmtPrdClsCd') == "02") {
    await $c.win.alert($p, "결제 구분은 Bill 수령후를 선택하실 수 없습니다.");
    return 0;
  }
  if (txt_clntTelNo.getValue().length == 0 && txt_clntMpNo.getValue().length == 0) {
    await $c.gus.cfAlertMsg($p, "유선전화와 휴대전화 둘 중 하나는 필수입력입니다 .");
    return false;
  }
  if ((await scwin.f_validate()) == false) {
    return;
  }
  if (!(await $c.win.confirm($p, MSG_CM_CRM_001))) {
    return; //저장하시겠습니까?
  }
  scwin.f_makePchsClntClsDataset();
  ds_clnt.setRowPosition(0);
  ds_busi.setRowPosition(0);
  ds_busi.setCellData(0, "crn", ed_crn.getValue());
  ds_busi.setCellData(0, "busiClsCd", lc_busiClsCd.getValue());
  $c.sbm.setAction($p, sbm_save, scwin.f_getSaveAction());
  $c.sbm.execute($p, sbm_save);
};
scwin.f_getSaveAction = function () {
  if (scwin.currentViewState == scwin.STATE_VIEW) {
    return "";
  }
  if (scwin.currentViewState == scwin.STATE_UPDATE) {
    return "/ncall.tn.cs.clntmgnt.UpdateClntCMD.do";
  } else {
    return "/ncall.tn.cs.clntmgnt.RegistClntCMD.do";
  }
};

