scwin.f_openZipPopUp = async function (pClose) {
  // 사업장주소 udc codeId, nameId
  var codeObj = ed_zip;
  var nameObj = txt_addr1;
  if (pClose == 'T' && !$c.gus.cfCanOpenPopup($p, codeObj, nameObj)) {
    return;
  }
  var rtnList = new Array();
  var opts = {
    id: "smpPop",
    popupName: "",
    modal: true,
    type: "browserPopup" //화면 오픈 타입 ("pageFramePopup", "browserPopup")
    ,

    title: "Win pop" //Layer pop
    ,

    width: 750,
    height: 600
  };
  var popupResult = await $c.win.openPopup($p, "/ui/cm/zz/zipcodePopupNcall.xml", opts);
  ed_zip.setValue(popupResult.zip); //출발지 우편번호
  txt_addr1.setValue(popupResult.addr1); //출발지 우편번호

  if (popupResult != null && popupResult[0] != "N/A" && busiZip_check) {
    // 청구지주소 udc
    ed_busiZip.setValue($c.gus.cfGetValue($p, codeObj));
    txt_busiAddr1.setValue($c.gus.cfGetValue($p, nameObj));
  }
};

//-------------------------------------------------------------------------
// 주소 수령지 팝업
//-------------------------------------------------------------------------
scwin.f_openBusiZipPopUp = async function (pClose) {
  var codeObj = ed_busiZip;
  var nameObj = txt_busiAddr1;
  if (pClose != 'F' && !$c.gus.cfCanOpenPopup($p, codeObj, nameObj)) {
    return;
  }
  var rtnList = new Array();
  var opts = {
    id: "smpPop",
    popupName: "",
    modal: true,
    type: "browserPopup" //화면 오픈 타입 ("pageFramePopup", "browserPopup")
    ,

    title: "Win pop" //Layer pop
    ,

    width: 750,
    height: 400
  };
  var popupResult = await $c.win.openPopup($p, "/ui/cm/zz/zipcodePopupNcall.xml", opts);
  if (popupResult != null) {
    if (popupResult[0] == "N/A") {
      return;
    }
    ed_busiZip.setValue(popupResult.zip); //출발지 우편번호
    txt_busiAddr1.setValue(popupResult.addr1); //출발지 우편번호

    if (popupResult != null && popupResult[0] != "N/A") {
      if (ed_zip.getValue() == ed_busiZip.getValue()) {
        busiZip_check.setValue("1");
      } else {
        busiZip_check.setValue("0");
      }
    }
  } else {
    ed_busiZip.setValue(""); //출발지 우편번호
    txt_busiAddr1.setValue(""); //출발지 우편번호
  }
};

