// 수금조건 행 삭제
scwin.f_ClntCollMoneyCondDelMarked = async function () {
  var rowIdx = ds_collMoneyCond.getRowPosition();
  if (ds_collMoneyCond.getCellData(rowIdx, "confirmYn") == "1") {
    await $c.gus.cfAlertMsg($p, "확인된 건은 삭제 할 수 없습니다.");
  } else {
    // ds_collMoneyCond.DeleteMarked();
    if (ds_collMoneyCond.getRowStatus(rowIdx) == "C") {
      ds_collMoneyCond.removeRow(rowIdx);
    } else {
      ds_collMoneyCond.deleteRow(rowIdx);
      ds_collMoneyCond.setFocusedCell(rowIdx, 0);
    }
  }
};

