//-------------------------------------------------------------------------
// ASIS : for=ds_member event=OnLoadCompleted(rowCnt)
//-------------------------------------------------------------------------
scwin.sbm_member_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) return; // OnFail

  var rowCnt = ds_member.getTotalRow();
  if (rowCnt == 0) {
    await $c.gus.cfAlertMsg($p, "회원정보가 없습니다.");
    scwin.f_close();
    return;
  }
  ds_clnt.removeAll();
  ds_busi.removeAll();
  ds_clnt.insertRow();
  ds_busi.insertRow();
  rd_copCoEstmtYn.setValue("0"); //협력업체평가여부 - 아니오
  chk_sellClntYn.setValue(["01", "02", "03"].includes(ds_member.getCellData(0, "mbrClsCd")) ? "1" : "0"); //매출거래처여부 - 화주,선사, 포워드
  chk_pchsClntYn.setValue(["04", "05"].includes(ds_member.getCellData(0, "mbrClsCd")) ? "1" : "0"); //매입거래처여부 - 화주,선사, 포워드
  chk_bizDivBulkYn.setValue(ds_member.getCellData(0, "bulkYn") == "1" ? "1" : "0"); // 벌크여부
  chk_bizDivCntrYn.setValue(ds_member.getCellData(0, "cntrYn") == "1" ? "1" : "0"); // 컨테이너여부
  lc_intrlnsClsCd.setValue("01"); //계열구분 - 타법인
  chk_bizDomTransYn.setValue(chk_sellClntYn.getValue()); // 사업영역 - 운송사업
  chk_transBizYn.setValue(chk_pchsClntYn.getValue()); // 운송사업부분 - 운송사업

  // 회원구분 코드 값에 따라 매출 거래처구분 변경, 운송사업부 변경, 거래처구분 변경
  switch (ds_member.getCellData(0, "mbrClsCd")) {
    case "01": //화주
    case "03":
      //포워드
      lc_sellClntClsCd.setValue("02"); // 화주
      break;
    case "02":
      //선사
      lc_sellClntClsCd.setValue("01");
    // 선사
  }
  $c.gus.f_CopyDataRow($p, ds_member, ds_clnt, 0, ds_clnt.getRowPosition(), ["busiNm", "tmcMbrId", "mbrNm", "telNo", "mpNo", "faxNo", "email"], ["clntNm", "mbrId", "clntPersNm", "clntTelNo", "clntMpNo", "clntFaxNo", "clntEmail"]);
  $c.gus.f_CopyDataRow($p, ds_member, ds_busi, 0, ds_busi.getRowPosition(), ["busiClsCd", "crn", "repstNm", "biztypeNm", "bizcondNm", "busiZip", "busiAddr1", "busiAddr2", "mailZip", "mailAddr1", "mailAddr2"], ["busiClsCd", "crn", "repstNm", "biztypeNm", "bizcondNm", "zip", "addr1", "addr2", "busiZip", "busiAddr1", "busiAddr2"]);
  scwin.f_ChangeCrnInputFormat(lc_busiClsCd.getValue());
  scwin.f_ChangeScreenState(scwin.STATE_CONVERT);
};

